// Group lookup helper
function vocabByGroup(g) {
  return VOCAB.filter(v => v.g === g);
}

function allGroups() {
  const groups = new Set(VOCAB.map(v => v.g));
  return Array.from(groups).sort((a, b) => a - b);
}
